#!/usr/bin/env python3
from __future__ import annotations

import argparse
import json
import os
import subprocess
import sys
from datetime import datetime, timezone
from pathlib import Path
from typing import Any


TASK_PARAMS = {
    "input_dir": "~/Desktop/pdf样本",
    "output_xlsx": "artifacts/outputs/trello_readonly/pdf_to_excel_from_trello.xlsx",
    "ocr": "auto",
    "dry_run": False,
    "origin_id": "trello:69c24cd3c1a2359ddd7a1bf8",
    "title": "BL-20260324-014 live preview smoke sample 2026-03-24 (best-effort reviewable attempt)",
    "description": "Purpose: | Controlled Trello live preview smoke for openclaw-team. | Expected behavior: | - read-only Trello ingest | - preview creation smoke only | - no business execution claim | - no Trello writeback expected in this step | Traceability: | - backlog: BL-20260324-014 | - blocker context: BL-20260324-015 | - created_by: Oscarling | - created_at: 2026-03-24 Asia/Shanghai | Note: | This card is only for governed smoke verification and should remain open until the smoke is finished.",
    "labels": ["best_effort", "evidence_backed", "readonly", "reviewable", "trello"],
    "preferred_base_script": "artifacts/scripts/pdf_to_excel_ocr.py",
    "reference_docs": [
        "artifacts/docs/pdf_to_excel_ocr_usage.md",
        "artifacts/reviews/pdf_to_excel_ocr_review.md"
    ]
}

DEFAULT_TIMEOUT_SECONDS = 900
SUCCESS_STATUSES = {"success", "ok", "completed"}
PARTIAL_STATUSES = {"partial", "warning", "dry_run", "no_input", "skipped"}


def utc_now() -> str:
    return datetime.now(timezone.utc).isoformat()


def repo_root() -> Path:
    return Path(__file__).resolve().parents[2]


def resolve_repo_path(value: str) -> Path:
    path = Path(os.path.expanduser(value))
    if path.is_absolute():
        return path
    return (repo_root() / path).resolve()


def discover_pdfs(input_dir: Path) -> list[Path]:
    if not input_dir.exists() or not input_dir.is_dir():
        return []
    return sorted(
        [p for p in input_dir.rglob("*") if p.is_file() and p.suffix.lower() == ".pdf"],
        key=lambda p: str(p).lower(),
    )


def load_json_file(path: Path) -> Any:
    with path.open("r", encoding="utf-8") as fh:
        return json.load(fh)


def find_delegate_report(stdout: str, stderr: str, output_xlsx: Path) -> Path | None:
    candidates: list[Path] = []
    for line in (stdout.splitlines() + stderr.splitlines()):
        stripped = line.strip()
        if not stripped:
            continue
        if stripped.endswith(".json"):
            maybe = Path(stripped)
            if maybe.exists() and maybe.is_file():
                candidates.append(maybe)
    derived = output_xlsx.with_suffix(output_xlsx.suffix + ".report.json")
    if derived.exists() and derived.is_file():
        candidates.append(derived)
    simple = output_xlsx.with_suffix(".json")
    if simple.exists() and simple.is_file():
        candidates.append(simple)
    for candidate in candidates:
        try:
            data = load_json_file(candidate)
        except Exception:
            continue
        if isinstance(data, dict):
            return candidate
    return None


def classify_delegate_result(report_data: dict[str, Any] | None, output_xlsx: Path, pdf_count: int, dry_run: bool) -> tuple[str, list[str]]:
    reasons: list[str] = []

    if dry_run:
        return "partial", ["dry_run requested; reviewable execution only"]

    if pdf_count == 0:
        return "partial", ["no PDF inputs discovered"]

    if report_data is None:
        reasons.append("delegate did not provide a structured JSON report with strong success evidence")
        return "partial", reasons

    raw_status = str(report_data.get("status", "")).strip().lower()
    processed = report_data.get("processed_files")
    succeeded = report_data.get("succeeded_files")
    failed = report_data.get("failed_files")
    output_path = report_data.get("output_xlsx") or report_data.get("output")

    processed_count = processed if isinstance(processed, int) else None
    succeeded_count = succeeded if isinstance(succeeded, int) else None
    failed_count = failed if isinstance(failed, int) else None

    if raw_status in SUCCESS_STATUSES:
        if processed_count is None and succeeded_count is None:
            reasons.append("delegate success status lacked processed/succeeded counters")
            return "partial", reasons
        evidence_count = succeeded_count if succeeded_count is not None else processed_count
        if not isinstance(evidence_count, int) or evidence_count < 1:
            reasons.append("delegate success status did not confirm at least one processed input")
            return "partial", reasons
        if isinstance(failed_count, int) and failed_count > 0:
            reasons.append("delegate reported failed files, so wrapper will not upgrade outcome to success")
            return "partial", reasons
        if output_path:
            try:
                resolved_report_output = resolve_repo_path(str(output_path)) if not Path(str(output_path)).is_absolute() else Path(str(output_path))
            except Exception:
                resolved_report_output = None
            if resolved_report_output is not None and resolved_report_output.resolve() != output_xlsx.resolve():
                reasons.append("delegate report output path does not match requested output_xlsx")
                return "partial", reasons
        if not output_xlsx.exists():
            reasons.append("delegate reported success but requested XLSX output does not exist")
            return "partial", reasons
        return "success", ["delegate report confirmed successful processing evidence"]

    if raw_status in PARTIAL_STATUSES:
        reasons.append(f"delegate reported reviewable non-success status: {raw_status}")
        return "partial", reasons

    if raw_status:
        reasons.append(f"delegate reported non-success status: {raw_status}")
        return "failed", reasons

    reasons.append("delegate report missing recognizable status field")
    return "partial", reasons


def build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(
        description="Reviewable inbox runner for repository PDF-to-Excel OCR helper"
    )
    parser.add_argument("--input-dir", default=TASK_PARAMS["input_dir"])
    parser.add_argument("--output-xlsx", default=TASK_PARAMS["output_xlsx"])
    parser.add_argument("--ocr", default=TASK_PARAMS["ocr"], choices=["auto", "on", "off"])
    parser.add_argument("--dry-run", action="store_true", default=bool(TASK_PARAMS["dry_run"]))
    parser.add_argument("--timeout-seconds", type=int, default=DEFAULT_TIMEOUT_SECONDS)
    return parser


def main() -> int:
    args = build_parser().parse_args()

    input_dir = Path(os.path.expanduser(args.input_dir)).resolve()
    output_xlsx = resolve_repo_path(args.output_xlsx)
    delegate_script = resolve_repo_path(TASK_PARAMS["preferred_base_script"])

    summary: dict[str, Any] = {
        "status": "failed",
        "title": TASK_PARAMS["title"],
        "origin_id": TASK_PARAMS["origin_id"],
        "labels": TASK_PARAMS["labels"],
        "description": TASK_PARAMS["description"],
        "requested": {
            "input_dir": str(input_dir),
            "output_xlsx": str(output_xlsx),
            "ocr": args.ocr,
            "dry_run": args.dry_run,
            "timeout_seconds": args.timeout_seconds,
        },
        "delegate": {
            "preferred_base_script": TASK_PARAMS["preferred_base_script"],
            "resolved_script": str(delegate_script),
        },
        "timestamps": {
            "started_at": utc_now(),
        },
        "notes": [],
        "artifacts": [],
    }

    if output_xlsx.suffix.lower() != ".xlsx":
        summary["status"] = "failed"
        summary["notes"].append("requested output path must end with .xlsx for workbook fidelity")
        summary["timestamps"]["finished_at"] = utc_now()
        print(json.dumps(summary, ensure_ascii=False, indent=2))
        return 2

    if not delegate_script.exists() or not delegate_script.is_file():
        summary["status"] = "failed"
        summary["notes"].append("reviewed delegate script was not found")
        summary["timestamps"]["finished_at"] = utc_now()
        print(json.dumps(summary, ensure_ascii=False, indent=2))
        return 2

    pdfs = discover_pdfs(input_dir)
    summary["discovery"] = {
        "input_dir_exists": input_dir.exists(),
        "input_dir_is_dir": input_dir.is_dir(),
        "pdf_count": len(pdfs),
        "sample_pdfs": [str(p) for p in pdfs[:10]],
    }

    if args.dry_run:
        summary["status"] = "partial"
        summary["notes"].append("dry_run requested; delegate execution skipped")
        summary["timestamps"]["finished_at"] = utc_now()
        print(json.dumps(summary, ensure_ascii=False, indent=2))
        return 0

    if len(pdfs) == 0:
        summary["status"] = "partial"
        summary["notes"].append("no PDF files discovered; no XLSX produced")
        summary["timestamps"]["finished_at"] = utc_now()
        print(json.dumps(summary, ensure_ascii=False, indent=2))
        return 0

    output_xlsx.parent.mkdir(parents=True, exist_ok=True)

    command = [
        sys.executable,
        str(delegate_script),
        "--input-dir",
        str(input_dir),
        "--output-xlsx",
        str(output_xlsx),
        "--ocr",
        str(args.ocr),
    ]

    summary["delegate"]["command"] = command

    try:
        completed = subprocess.run(
            command,
            cwd=str(repo_root()),
            capture_output=True,
            text=True,
            timeout=max(1, int(args.timeout_seconds)),
            check=False,
        )
    except subprocess.TimeoutExpired as exc:
        summary["status"] = "failed"
        summary["notes"].append(f"delegate timed out after {max(1, int(args.timeout_seconds))} seconds")
        summary["delegate"]["timeout"] = {
            "seconds": max(1, int(args.timeout_seconds)),
            "stdout": exc.stdout,
            "stderr": exc.stderr,
        }
        summary["timestamps"]["finished_at"] = utc_now()
        print(json.dumps(summary, ensure_ascii=False, indent=2))
        return 3

    summary["delegate"]["returncode"] = completed.returncode
    summary["delegate"]["stdout_tail"] = completed.stdout.splitlines()[-50:]
    summary["delegate"]["stderr_tail"] = completed.stderr.splitlines()[-50:]

    report_path = find_delegate_report(completed.stdout, completed.stderr, output_xlsx)
    report_data = None
    if report_path is not None:
        try:
            report_data = load_json_file(report_path)
            summary["delegate"]["report_path"] = str(report_path)
            summary["delegate"]["report"] = report_data
        except Exception as exc:
            summary["notes"].append(f"failed to parse delegate report: {exc}")

    status, reasons = classify_delegate_result(report_data, output_xlsx, len(pdfs), args.dry_run)
    summary["status"] = status
    summary["notes"].extend(reasons)

    if output_xlsx.exists() and status == "success":
        summary["artifacts"].append(str(output_xlsx))
    elif output_xlsx.exists() and status != "success":
        summary["notes"].append("output workbook exists but wrapper is not claiming success without stronger delegate evidence")

    if completed.returncode != 0 and status == "success":
        summary["status"] = "partial"
        summary["notes"].append("delegate exited non-zero; wrapper downgraded outcome despite report evidence")

    if completed.returncode != 0 and status == "failed":
        summary["notes"].append("delegate exited with non-zero status")

    summary["timestamps"]["finished_at"] = utc_now()
    print(json.dumps(summary, ensure_ascii=False, indent=2))
    return 0 if summary["status"] in {"success", "partial"} else 1


if __name__ == "__main__":
    raise SystemExit(main())

#!/usr/bin/env python3
"""
Batch PDF -> Excel extractor with optional OCR fallback.

Design goals:
- Batch processing with per-file isolation (single file failure must not stop the batch)
- OCR mode: auto | on | off
- Chinese-friendly OCR defaults (chi_sim+eng)
- Dry-run support for pilot validation when dependencies are unavailable
"""

from __future__ import annotations

import argparse
import json
import shutil
import sys
from dataclasses import asdict, dataclass
from pathlib import Path
from typing import Any


try:
    from pypdf import PdfReader  # type: ignore
except Exception:
    PdfReader = None

try:
    import pandas as pd  # type: ignore
except Exception:
    pd = None

try:
    import pytesseract  # type: ignore
except Exception:
    pytesseract = None

try:
    from pdf2image import convert_from_path  # type: ignore
except Exception:
    convert_from_path = None


@dataclass
class FileResult:
    file_name: str
    file_path: str
    status: str
    extract_method: str
    page_count: int
    text_chars: int
    text_preview: str
    warnings: str
    error: str


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(description="Batch PDF to Excel extractor with OCR fallback.")
    parser.add_argument("--input-dir", required=True, help="Directory containing PDF files.")
    parser.add_argument("--output-xlsx", required=True, help="Output Excel path.")
    parser.add_argument(
        "--ocr",
        choices=("auto", "on", "off"),
        default="auto",
        help="OCR mode. auto=use OCR when plain text extraction is weak.",
    )
    parser.add_argument(
        "--dry-run",
        action="store_true",
        help="Do not write Excel file. Print execution summary only.",
    )
    parser.add_argument(
        "--ocr-lang",
        default="chi_sim+eng",
        help="OCR language pack for pytesseract, default supports Chinese + English.",
    )
    parser.add_argument(
        "--auto-ocr-min-chars",
        type=int,
        default=50,
        help="In auto mode, run OCR when extracted text chars < this threshold.",
    )
    return parser.parse_args()


def discover_pdfs(input_dir: Path) -> list[Path]:
    if not input_dir.exists():
        raise FileNotFoundError(f"Input directory does not exist: {input_dir}")
    if not input_dir.is_dir():
        raise NotADirectoryError(f"Input path is not a directory: {input_dir}")
    files = sorted([p for p in input_dir.rglob("*") if p.is_file() and p.suffix.lower() == ".pdf"])
    return files


def detect_ocr_runtime_status() -> tuple[str, list[str]]:
    missing: list[str] = []
    present: list[str] = []

    if pytesseract is None:
        missing.append("python module pytesseract")
    else:
        present.append("python module pytesseract")
    if convert_from_path is None:
        missing.append("python module pdf2image")
    else:
        present.append("python module pdf2image")
    if shutil.which("tesseract") is None:
        missing.append("binary tesseract")
    else:
        present.append("binary tesseract")
    if shutil.which("pdftoppm") is None:
        missing.append("binary pdftoppm (poppler)")
    else:
        present.append("binary pdftoppm (poppler)")

    if not missing:
        return "available", []
    if present:
        return "partial", missing
    return "blocked", missing


def extract_text_pypdf(pdf_path: Path) -> tuple[str, int]:
    if PdfReader is None:
        raise RuntimeError("pypdf not installed")
    reader = PdfReader(str(pdf_path))
    page_texts: list[str] = []
    for page in reader.pages:
        text = page.extract_text() or ""
        page_texts.append(text)
    return "\n".join(page_texts), len(reader.pages)


def extract_text_ocr(pdf_path: Path, ocr_lang: str) -> str:
    if pytesseract is None:
        raise RuntimeError("pytesseract not installed")
    if convert_from_path is None:
        raise RuntimeError("pdf2image not installed")
    if shutil.which("tesseract") is None:
        raise RuntimeError("tesseract binary not found")
    if shutil.which("pdftoppm") is None:
        raise RuntimeError("pdftoppm binary not found (install poppler)")

    images = convert_from_path(str(pdf_path), dpi=220)
    chunks: list[str] = []
    for image in images:
        chunks.append(pytesseract.image_to_string(image, lang=ocr_lang))
    return "\n".join(chunks)


def compact_preview(text: str, limit: int = 160) -> str:
    single_line = " ".join(text.split())
    if len(single_line) <= limit:
        return single_line
    return single_line[: limit - 3] + "..."


def process_one_pdf(
    pdf_path: Path,
    ocr_mode: str,
    ocr_lang: str,
    auto_ocr_min_chars: int,
) -> FileResult:
    warnings: list[str] = []
    errors: list[str] = []
    method = "none"
    text = ""
    page_count = 0

    try:
        text, page_count = extract_text_pypdf(pdf_path)
        method = "text"
    except Exception as e:
        warnings.append(f"text extraction unavailable: {e}")

    needs_ocr = False
    if ocr_mode == "on":
        needs_ocr = True
    elif ocr_mode == "auto" and len(text.strip()) < auto_ocr_min_chars:
        needs_ocr = True

    if needs_ocr:
        try:
            ocr_text = extract_text_ocr(pdf_path, ocr_lang).strip()
            if ocr_text:
                if text.strip():
                    text = f"{text.strip()}\n\n[OCR Fallback]\n{ocr_text}"
                    method = "text+ocr"
                else:
                    text = ocr_text
                    method = "ocr"
            else:
                warnings.append("OCR returned empty text")
        except Exception as e:
            errors.append(f"OCR failed: {e}")

    if not text.strip():
        if errors:
            status = "failed"
        else:
            status = "partial"
            warnings.append("No extractable text captured")
    else:
        status = "success"

    return FileResult(
        file_name=pdf_path.name,
        file_path=str(pdf_path),
        status=status,
        extract_method=method,
        page_count=page_count,
        text_chars=len(text),
        text_preview=compact_preview(text),
        warnings=" | ".join(warnings),
        error=" | ".join(errors),
    )


def write_excel(results: list[FileResult], output_xlsx: Path) -> None:
    if pd is None:
        raise RuntimeError("pandas is required to write Excel output")
    output_xlsx.parent.mkdir(parents=True, exist_ok=True)

    rows = [asdict(r) for r in results]
    detail_df = pd.DataFrame(rows)

    summary_rows: list[dict[str, Any]] = []
    by_status = detail_df.groupby("status").size().to_dict()
    by_method = detail_df.groupby("extract_method").size().to_dict()
    for key, value in sorted(by_status.items()):
        summary_rows.append({"metric": "status_count", "name": key, "value": int(value)})
    for key, value in sorted(by_method.items()):
        summary_rows.append({"metric": "method_count", "name": key, "value": int(value)})
    summary_rows.append({"metric": "total_files", "name": "all", "value": int(len(results))})
    summary_df = pd.DataFrame(summary_rows)

    with pd.ExcelWriter(output_xlsx) as writer:
        summary_df.to_excel(writer, sheet_name="summary", index=False)
        detail_df.to_excel(writer, sheet_name="files", index=False)


def main() -> int:
    args = parse_args()
    input_dir = Path(args.input_dir).expanduser().resolve()
    output_xlsx = Path(args.output_xlsx).expanduser().resolve()

    try:
        pdf_files = discover_pdfs(input_dir)
    except Exception as e:
        print(json.dumps({"status": "failed", "error": str(e)}, ensure_ascii=False, indent=2))
        return 2

    if not pdf_files:
        print(
            json.dumps(
                {
                    "status": "failed",
                    "error": f"No PDF files found under {input_dir}",
                },
                ensure_ascii=False,
                indent=2,
            )
        )
        return 2

    ocr_runtime, missing = detect_ocr_runtime_status()
    results: list[FileResult] = []
    for pdf in pdf_files:
        try:
            results.append(
                process_one_pdf(
                    pdf,
                    ocr_mode=args.ocr,
                    ocr_lang=args.ocr_lang,
                    auto_ocr_min_chars=args.auto_ocr_min_chars,
                )
            )
        except Exception as e:
            results.append(
                FileResult(
                    file_name=pdf.name,
                    file_path=str(pdf),
                    status="failed",
                    extract_method="none",
                    page_count=0,
                    text_chars=0,
                    text_preview="",
                    warnings="",
                    error=f"Unhandled processing exception: {e}",
                )
            )

    status_counter: dict[str, int] = {}
    for item in results:
        status_counter[item.status] = status_counter.get(item.status, 0) + 1

    report = {
        "status": "success" if status_counter.get("failed", 0) == 0 else "partial",
        "input_dir": str(input_dir),
        "output_xlsx": str(output_xlsx),
        "ocr_mode": args.ocr,
        "ocr_runtime_status": ocr_runtime,
        "ocr_missing_dependencies": missing,
        "total_files": len(results),
        "status_counter": status_counter,
        "dry_run": bool(args.dry_run),
    }

    if args.dry_run:
        print(json.dumps(report, ensure_ascii=False, indent=2))
        return 0

    try:
        write_excel(results, output_xlsx)
        print(json.dumps(report, ensure_ascii=False, indent=2))
        return 0
    except Exception as e:
        report["status"] = "failed"
        report["error"] = str(e)
        print(json.dumps(report, ensure_ascii=False, indent=2))
        return 3


if __name__ == "__main__":
    raise SystemExit(main())
